const e=JSON.parse('{"key":"v-c348a0e6","path":"/learn-typescript/4.html","title":"递归复用","lang":"zh-CN","frontmatter":{"title":"递归复用","date":"2023-01-09T13:36:24.000Z","tag":["learn","TypeScript"],"category":["TypeScript"],"description":"递归复用","footer":true},"headers":[{"level":2,"title":"递归复用","slug":"递归复用","link":"#递归复用","children":[]},{"level":2,"title":"Promise 的递归复用","slug":"promise-的递归复用","link":"#promise-的递归复用","children":[{"level":3,"title":"DeepPromiseValueType","slug":"deeppromisevaluetype","link":"#deeppromisevaluetype","children":[]}]},{"level":2,"title":"数组类型的递归","slug":"数组类型的递归","link":"#数组类型的递归","children":[{"level":3,"title":"ReverseArr","slug":"reversearr","link":"#reversearr","children":[]},{"level":3,"title":"Includes","slug":"includes","link":"#includes","children":[]},{"level":3,"title":"RemoveItem","slug":"removeitem","link":"#removeitem","children":[]},{"level":3,"title":"BuildArray","slug":"buildarray","link":"#buildarray","children":[]}]},{"level":2,"title":"字符串类型的递归","slug":"字符串类型的递归","link":"#字符串类型的递归","children":[{"level":3,"title":"ReplaceAll","slug":"replaceall","link":"#replaceall","children":[]},{"level":3,"title":"StringToUnion","slug":"stringtounion","link":"#stringtounion","children":[]},{"level":3,"title":"ReverseStr","slug":"reversestr","link":"#reversestr","children":[]}]},{"level":2,"title":"对象类型的递归","slug":"对象类型的递归","link":"#对象类型的递归","children":[{"level":3,"title":"DeepReadonly","slug":"deepreadonly","link":"#deepreadonly","children":[]}]},{"level":2,"title":"总结","slug":"总结","link":"#总结","children":[]}],"git":{"createdTime":1673246108000,"updatedTime":1673246849000,"contributors":[{"name":"wangmaoquan","email":"1782976211@qq.com","commits":2}]},"readingTime":{"minutes":4.14,"words":1243},"filePathRelative":"learn-typescript/4.md","localizedDate":"2023年1月9日","excerpt":"<h2> 递归复用</h2>\\n<p>针对 提取或构造的<code>数组元素个数不确定</code>、<code>字符串长度不确定</code>、<code>对象层数不确定</code></p>\\n<p>递归是把问题分解为一系列相似的小问题，通过函数不断调用自身来解决这一个个小问题，直到满足结束条件，就完成了问题的求解</p>\\n<p>TypeScript 类型系统<code>不支持循环</code>，但支持递归。当处理数量（个数、长度、层数）不固定的类型的时候，可以只处理一个类型，然后递归的调用自身处理下一个类型，直到结束条件也就是所有的类型都处理完了，就完成了不确定数量的类型编程，达到循环的效果</p>\\n"}');export{e as data};
